DROP TABLE IF EXISTS `hrm_employee_master`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `hrm_employee_master` (
  `employee_master_id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL,
  `emp_code` varchar(255) NOT NULL,
  `name` varchar(255) NOT NULL,
  `phone` varchar(255) NOT NULL,
  `address` varchar(255) NOT NULL,
  `email` varchar(255) NOT NULL,
  `department` varchar(255) NOT NULL,
  `position` varchar(255) NOT NULL,
  `monthly_wages` decimal(10,2) NOT NULL,
  `location_id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `isActive` tinyint(1) DEFAULT 1,
  `supervisor_id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `userId` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  `reporting_manager_id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  PRIMARY KEY (`employee_master_id`),
  UNIQUE KEY `emp_code` (`emp_code`),
  UNIQUE KEY `phone` (`phone`),
  UNIQUE KEY `email` (`email`),
  KEY `location_id` (`location_id`),
  KEY `supervisor_id` (`supervisor_id`),
  KEY `userId` (`userId`),
  KEY `reporting_manager_id` (`reporting_manager_id`),
  CONSTRAINT `hrm_employee_master_ibfk_1` FOREIGN KEY (`location_id`) REFERENCES `OfficeLocation` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `hrm_employee_master_ibfk_2` FOREIGN KEY (`supervisor_id`) REFERENCES `hrm_employee_master` (`employee_master_id`),
  CONSTRAINT `hrm_employee_master_ibfk_3` FOREIGN KEY (`userId`) REFERENCES `Users` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `hrm_employee_master_ibfk_4` FOREIGN KEY (`reporting_manager_id`) REFERENCES `hrm_employee_master` (`employee_master_id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

