CREATE TABLE `inventory_stock_levels` (
  `id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL,
  `ProductId` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL,
  `WarehouseId` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL,
  `manufacturer_id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Kis manufacturer ka stock hai',
  `color` varchar(255) DEFAULT 'Standard' COMMENT 'Product ka rang (e.g., Red, Blue, #001aff)',
  `current_quantity` decimal(15,3) DEFAULT 0.000,
  `reserved_quantity` decimal(15,3) DEFAULT 0.000,
  `last_updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_stock_idx` (`ProductId`,`WarehouseId`,`manufacturer_id`,`color`),
  KEY `WarehouseId` (`WarehouseId`),
  CONSTRAINT `inventory_stock_levels_ibfk_1` FOREIGN KEY (`ProductId`) REFERENCES `inventory_products` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `inventory_stock_levels_ibfk_2` FOREIGN KEY (`WarehouseId`) REFERENCES `inventory_warehouses` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
