--
-- Table structure for table `inventory_transactions`
--

DROP TABLE IF EXISTS `inventory_transactions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `inventory_transactions` (
  `id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL,
  `type` enum('INWARD','OUTWARD','RETURN','DAMAGE','ADJUSTMENT') NOT NULL,
  `date` datetime NOT NULL,
  `ProductId` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL,
  `WarehouseId` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL,
  `partner_id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Link to Supplier or Customer',
  `manufacturer_id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Track which manufacturer''s stock is moving',
  `quantity` decimal(15,3) NOT NULL,
  `unit_price` decimal(15,2) NOT NULL DEFAULT 0.00,
  `batch_number` varchar(255) DEFAULT NULL,
  `reference_no` varchar(255) DEFAULT NULL,
  `movement_date` datetime NOT NULL,
  `status` enum('PENDING','COMPLETED','CANCELLED') NOT NULL DEFAULT 'COMPLETED',
  `remarks` text DEFAULT NULL,
  `created_by` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL,
  `createdAt` datetime NOT NULL,
  PRIMARY KEY (`id`),
  KEY `inventory_transactions_type` (`type`),
  KEY `inventory_transactions__product_id` (`ProductId`),
  KEY `inventory_transactions__warehouse_id` (`WarehouseId`),
  KEY `inventory_transactions_partner_id` (`partner_id`),
  KEY `inventory_transactions_manufacturer_id` (`manufacturer_id`),
  KEY `inventory_transactions_batch_number` (`batch_number`),
  KEY `inventory_transactions_movement_date` (`movement_date`),
  CONSTRAINT `inventory_transactions_ibfk_1` FOREIGN KEY (`ProductId`) REFERENCES `inventory_products` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `inventory_transactions_ibfk_2` FOREIGN KEY (`WarehouseId`) REFERENCES `inventory_warehouses` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `inventory_transactions_ibfk_3` FOREIGN KEY (`partner_id`) REFERENCES `inventory_partners` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
